<template>
  <div class="products">
    <div class="products_title">{{ shopName }}</div>
    <div class="products_wrapper">
      <div class="products_list">
        <div
          class="products_item"
          v-for="item in productList"
        :key="item._id"
        >
          <img :src="item.imgUrl" />
          <div class="products_item_detail">
            <h4 class="products_item_title">{{ item.name }}</h4>
            <p class="products_item_price">
              <div class="products_item_single">
                <span class="products_item_yen">&yen;</span>
                {{ item.price }} x {{ item.count }}
              </div>
              <div class="products_item_total">
                <span class="products_item_yen">&yen;</span>
                {{ (item.price * item.count).toFixed(2) }}
              </div>
            </p>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { useRoute } from 'vue-router'
import { useCommonCartEffect } from '../../effects/cartEffects'

export default {
  name: 'ProductList',
  setup() {
    const route = useRoute()
    const shopId = route.params.id
    const { shopName, productList } = useCommonCartEffect(shopId)

    return { shopName, productList }
  }
}
</script>

<style lang="scss" scoped>
  @import "../../styles/variables.scss";
  @import "../../styles/mixins.scss";
  .products {
    margin: .16rem .18rem .2rem .18rem;
    background: #fff;
    &_title {
      padding: .16rem;
      font-size: .16rem;
      color: #333;
    }
    &_wrapper {
      overflow-y: scroll;
      position: absolute;
      left: 0;
      right: 0;
      bottom: .6rem;
      top: 2.6rem;
      margin: 0 .18rem;
    }
    &_list {
      background-color: #fff;
    }
    &_item {
      display: flex;
      position: relative;
      padding: 0 .16rem .16rem .16rem;
      img {
        width: .46rem;
        height: .46rem;
        margin-right: 0.16rem;
      }
      &_detail {
        flex: 1;
      }
      &_title {
        margin: 0;
        line-height: 0.2rem;
        font-size: 0.14rem;
        color: #333;
        @include ellipses;
      }
      &_price {
        display: flex;
        margin: .06rem 0 0 0;
        line-height: 0.2rem;
        font-size: 0.14rem;
        color: $hightlight-fontColor;
      }
      &_total {
        flex: 1;
        text-align: right;
        color: #000;
      }
      &_yen {
        font-size: 0.12rem;
      }
    }
  }
</style>