<template>
  <div class="order">
    <div class="order_price">实付金额 <b>¥{{ calculations.price }}</b></div>
    <div class="order_btn" @click="handleSubmitClick(true)">提交订单</div>
  </div>
  <div
    class="mask"
    @click="handleSubmitClick(false)"
    v-show="showConfirm"
  >
    <div class="mask_content" @click.stop>
      <h3 class="mask_content_title">确认要离开收银台?</h3>
      <p class="mask_content_desc">请尽快完成支付,否则将被取消</p>
      <div class="mask_content_btns">
        <div
          class="mask_content_btn mask_content_btn-cancel"
          @click="handleConfirmOrder(true)"
        >取消订单</div>
        <div
          class="mask_content_btn mask_content_btn-confirm"
          @click="handleConfirmOrder(false)"
        >确认支付</div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useStore } from 'vuex'
import { useCommonCartEffect } from '../../effects/cartEffects'
import { post } from '../../utils/request'

const useMakeOrderEffect = (shopName, productList) => {  // 下单相关逻辑
  const router = useRouter()
  const store = useStore()
  const handleConfirmOrder = async (isCanceled) => {
    const products = []
    for (let i in productList.value) {
      const product = productList.value[i]
      products.push({ id: ~~product._id, num: product.count })
    }
    console.log('products >>> ', products)
    try {
      const result = await post('/api/order', {
        addressId: 1,
        shopId,
        shopName: shopName.value,
        isCanceled,
        products
      })
      if (result?.errno === 0) {
        store.commit('clearCartData', shopId)
        router.push({ path: '/orderList' })
      } else {
        alert('失败')
      }
    } catch(e) {}
  }

  return { handleConfirmOrder }
}

const useShowMaskEffect = () => {  // 蒙层相关逻辑
  const showConfirm = ref(false)
  const handleSubmitClick = (status) => {
    showConfirm.value = status
  }

  return { showConfirm, handleSubmitClick }
}

export default {
  name: 'Order',
  setup() {
    const route = useRoute()
    
    const shopId = parseInt(route.params.id, 10)
    const { shopName, productList, calculations } = useCommonCartEffect(shopId)
    const { handleConfirmOrder } = useMakeOrderEffect(shopId, shopName, productList)
    const { showConfirm, handleSubmitClick } = useShowMaskEffect()
    
    
    return { showConfirm, calculations, handleConfirmOrder, handleSubmitClick }
  }
}
</script>

<style lang="scss" scoped>
  .order {
    position: absolute;
    left: 0;
    right: 0;
    bottom: 0;
    display: flex;
    height: .49rem;
    line-height: .49rem;
    background-color: #fff;
    &_price {
      flex: 1;
      text-indent: .24rem;
      font-size: .14rem;
      color: #333;
    }
    &_btn {
      width: .98rem;
      background: #4fb0f9;
      color: #fff;
      text-align: center;
      font-size: .14rem;
    }
  }
  .mask {
    z-index: 1;
    position: absolute;
    left: 0;
    right: 0;
    bottom: 0;
    top: 0;
    background: rgba(0, 0, 0, .5);
    &_content {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 3rem;
      height: 1.56rem;
      border-radius: .04rem;
      background: #fff;
      text-align: center;
      &_title {
        margin: .24rem 0 0 0;
        line-height: .26rem;
        font-size: .18rem;
        color: #333;
      }
      &_desc {
        margin: .08rem 0 0 0;
        font-size: .14rem;
        color: #666;
      }
      &_btns {
        display: flex;
        margin: .24rem .58rem;
      }
      &_btn {
        flex: 1;
        width: .8rem;
        line-height: .32rem;
        border-radius: .16rem;
        font-size: .14rem;
        &-cancel {
          margin-right: .12rem;
          color: #4fb0f9;
          border: 1px solid #4fb0f9;
        }
        &-confirm {
          margin-left: .12rem;
          color: #fff;
          background: #4fb0f9;
        }
      }
    }
  }
</style>